const input = $input.first().json;
const body = input.body || input; 
const headers = input.headers || {};

// Função para tratar strings
const str = k => (body && body[k] !== undefined && body[k] !== null) ? body[k].toString().trim() : '';

// Função para tratar NÚMEROS (evita erro numeric "")
const num = k => {
  const value = body[k];
  if (value === undefined || value === null || value.toString().trim() === "") {
    return null;
  }
  const cleanValue = value.toString().replace(/[R$\s.]/g, '').replace(',', '.');
  const parsed = parseFloat(cleanValue);
  return isNaN(parsed) ? null : parsed;
};

// --- NOVA FUNÇÃO PARA TRATAR DATAS (evita erro date "") ---
const dte = k => {
  const value = body[k];
  if (value === undefined || value === null || value.toString().trim() === "") {
    return null; // Retorna nulo para o Supabase aceitar
  }
  return value; // Retorna a data original (YYYY-MM-DD)
};

// --- LÓGICA DE EXTRAÇÃO DO ID (REFERER) ---
let idExtraido = body.id_url || '';

if (!idExtraido) {
  try {
    const referer = headers['referer'] || '';
    if (referer) {
      const matchForm = referer.match(/\/form\/([a-z0-9-]+)/i);
      const matchQuery = referer.match(/\?([a-z0-9-]{36})/i);
      idExtraido = (matchForm && matchForm[1]) || (matchQuery && matchQuery[1]) || '';
    }
  } catch (e) {}
}

const campos = {
  id_url:             idExtraido,
  // Bloco 1
  nome:                str('nome'),
  email:               str('email'),
  telefone:            str('telefone'),
  cpf:                 str('cpf'),
  nascimento:          dte('nascimento'),
  endereco:            str('endereco'),
  tem_filhos:          str('tem_filhos'),
  filhos:              Array.isArray(body.filhos) ? body.filhos : [],

  // Bloco 2
  renda_mensal:        num('renda_mensal'),
  patrimonio_total:    num('patrimonio_total'),
  valor_aplicacoes:    num('valor_aplicacoes'),
  valor_dividas:       num('valor_dividas'),

  // Bloco 3
  pct_pj:              num('pct_pj'),
  pct_pf:              num('pct_pf'),
  categorias_impacto:  str('categorias_impacto'),
  modelo_ir:           str('modelo_ir'),

  // Bloco 4
  tem_aporte:          str('tem_aporte'),
  valor_aporte:        num('valor_aporte'),
  tipos_investimento:  str('tipos_investimento'),
  perfil_investidor:   str('perfil_investidor'),

  // Bloco 5
  seguranca_familiar:  str('seguranca_familiar'),
  tem_blindagem:       str('tem_blindagem'),
  tem_seguros:         str('tem_seguros'),
  quais_seguros:       str('quais_seguros'),

  // Bloco 6
  objetivo_curto:       str('objetivo_curto'),
  objetivo_medio:       str('objetivo_medio'),
  objetivo_longo:       str('objetivo_longo'),
  hobbies:              str('hobbies'),
  planejamento_valeria: str('planejamento_valeria'),

  tem_atrasos:         str('tem_atrasos'),
};

// --- VALIDAÇÃO BÁSICA ---
const erros = [];
if (!campos.nome) erros.push('Nome é obrigatório.');

// --- TRATAMENTO DE DATA E FUSO (BRT -3h) ---
const data = new Date();
// Subtrai 3 horas para converter UTC para Brasília antes do ISO
const agora = new Date(data.getTime() - (3 * 60 * 60 * 1000)).toISOString().replace('Z', '');

return [{ 
  json: { 
    ...campos, 
    recebidoEm: agora, 
    valido: erros.length === 0, 
    erros 
  } 
}];

